$base = "D:\ClaudeCode\ngl-frac-spread"

Write-Host "Adding GitHub Pages deployment...`n" -ForegroundColor Cyan

$p = Join-Path $base ".github\workflows\deploy.yml"; $d = Split-Path $p
if (!(Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null }
[System.IO.File]::WriteAllBytes($p, [System.Convert]::FromBase64String(""))
Write-Host "  created: .github\workflows\deploy.yml" -ForegroundColor Green

$p = Join-Path $base "vite.config.js"; $d = Split-Path $p
if (!(Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null }
[System.IO.File]::WriteAllBytes($p, [System.Convert]::FromBase64String(""))
Write-Host "  created: vite.config.js" -ForegroundColor Green

Write-Host "\nDone! Now commit and push in GitHub Desktop." -ForegroundColor Green
